1	// Xianjun jiao. putaoshu@msn.com; xianjun.jiao@imec.be;
2	`include "clock_speed.v"
3	`include "board_def.v"
4	
5	`include "xpu_pre_def.v"
6	
7	`ifdef XPU_ENABLE_DBG
8	`define DEBUG_PREFIX (*mark_debug="true",DONT_TOUCH="TRUE"*)
9	`else
10	`define DEBUG_PREFIX
11	`endif
12	
13	`timescale 1 ns / 1 ps
14	
15		module tx_control #
16		(
17		   parameter integer RSSI_HALF_DB_WIDTH = 11,
18		   parameter integer C_S00_AXIS_TDATA_WIDTH	= 64,
19	     parameter integer WIFI_TX_BRAM_ADDR_WIDTH = 10
20		)
21		(
22	        input wire clk,
23	        input wire rstn,
24	        
25	        input wire ack_tx_disable,
26	        input wire [6:0] preamble_sig_time,
27	        input wire [4:0] ofdm_symbol_time,
28	        input wire [6:0] sifs_time,
29	        input wire [3:0] max_num_retrans,
30	        input wire tx_pkt_need_ack,
31	        input wire [3:0] tx_pkt_retrans_limit,
32	        input wire tx_ht_aggr,
33	        `DEBUG_PREFIX input wire [6:0]  relative_decoding_latency,
34	        `DEBUG_PREFIX input wire [14:0] send_ack_wait_top,
35	        `DEBUG_PREFIX input wire [14:0] recv_ack_timeout_top_adj,
36	        `DEBUG_PREFIX input wire [14:0] recv_ack_sig_valid_timeout_top,
37	        input wire recv_ack_fcs_valid_disable,
38		      `DEBUG_PREFIX input wire tx_core_is_ongoing,
39	        `DEBUG_PREFIX input wire pulse_tx_bb_end,
40	        `DEBUG_PREFIX input wire phy_tx_done,
41	        `DEBUG_PREFIX input wire sig_valid,
42	        `DEBUG_PREFIX input wire [7:0] signal_rate,
43	        `DEBUG_PREFIX input wire [15:0] signal_len,
44	        `DEBUG_PREFIX input wire fcs_valid,
45	        `DEBUG_PREFIX input wire fcs_in_strobe,
46	        `DEBUG_PREFIX input wire [1:0] FC_type,
47	        `DEBUG_PREFIX input wire [3:0] FC_subtype,
48	        input wire       FC_more_frag,
49	        input wire cts_torts_disable,
50	        input wire [4:0]  cts_torts_rate,
51	        input wire [15:0] duration_extra,
52	        input wire [15:0] duration,
53	        input wire [47:0] addr2,
54	        input wire [47:0] self_mac_addr,
55	        input wire [47:0] addr1,
56	        input wire [63:0] douta,
57	        input wire cts_toself_bb_is_ongoing,//this should rise before the phy tx end valid of phy tx IP core.
58	        `DEBUG_PREFIX input wire backoff_done,
59	        input wire [(WIFI_TX_BRAM_ADDR_WIDTH-1):0] bram_addr,
60	
61	        input wire ampdu_rx_tid_disable,
62	        input wire [3:0] ampdu_rx_tid,
63	        input wire ampdu_rx_start,
64	
65	        input wire [11:0] SC_seq_num,
66	        input wire rx_ht_aggr,
67	        input wire rx_ht_aggr_last,
68	
69	        input wire [15:0] blk_ack_req_ctrl,
70	        input wire [15:0] blk_ack_req_ssc,
71	        input wire [11:0] blk_ack_resp_ssn,
72	        input wire [63:0] blk_ack_resp_bitmap,
73	        input wire [3:0] qos_tid,
74	        input wire [1:0] qos_ack_policy,
75	
76	        output wire [3:0] tx_control_state_out,
77	        output wire tx_control_state_idle,
78	        output wire ack_cts_is_ongoing,
79	        `DEBUG_PREFIX output reg retrans_in_progress,
80	        `DEBUG_PREFIX output reg start_retrans,
81	        `DEBUG_PREFIX input wire quit_retrans,
82	        `DEBUG_PREFIX output reg start_tx_ack,
83	        `DEBUG_PREFIX output reg retrans_trigger,
84	        `DEBUG_PREFIX output reg tx_try_complete,
85	        `DEBUG_PREFIX output reg [79:0] tx_status,
86	        `DEBUG_PREFIX output reg ack_tx_flag,
87	        `DEBUG_PREFIX output reg wea,
88	        `DEBUG_PREFIX output reg [9:0] addra,
89	        output reg [(C_S00_AXIS_TDATA_WIDTH-1):0] dina
90		);
91	
92	  localparam [3:0]    IDLE =                     4'b0000,
93	                      PREP_ACK=                  4'b0001,
94	                      SEND_DFL_ACK=              4'b0010,
95	                      SEND_BLK_ACK=              4'b0011,
96	                      RECV_ACK_WAIT_TX_BB_DONE = 4'b0100,
97	                      RECV_ACK_WAIT_SIG_VALID =  4'b0101,
98	                      RECV_ACK  =                4'b0110;
99	
100	  `DEBUG_PREFIX wire [3:0] retrans_limit;
101	  `DEBUG_PREFIX reg [3:0] num_retrans;
102	  `DEBUG_PREFIX reg [14:0] ack_timeout_count;
103	  `DEBUG_PREFIX reg [2:0] send_ack_count;
104	  reg [47:0] ack_addr;
105	  reg signed [15:0] duration_received;
106	  reg signed [15:0] duration_standard;
107	  `DEBUG_PREFIX reg FC_more_frag_received;
108	  `DEBUG_PREFIX reg [3:0] tx_control_state;
109	  `DEBUG_PREFIX reg [3:0] tx_control_state_old;
110	  `DEBUG_PREFIX reg [3:0] num_retrans_lock;
111	  reg [11:0] blk_ack_resp_ssn_lock;
112	  reg [63:0] blk_ack_bitmap_lock;
113	  `DEBUG_PREFIX wire is_data;
114	  `DEBUG_PREFIX wire is_qosdata;
115	  `DEBUG_PREFIX wire is_management;
116	  `DEBUG_PREFIX wire is_blockackreq;
117	  `DEBUG_PREFIX wire is_blockackresp;
118	  `DEBUG_PREFIX wire is_pspoll;
119	  `DEBUG_PREFIX wire is_rts;
120	  `DEBUG_PREFIX wire is_ack;
121	  reg  [3:0] ackcts_rate;
122	  wire ackcts_signal_parity;
123	  wire [11:0] ackcts_signal_len;
124	  wire [11:0] blkack_signal_len;
125	  wire [3:0] blk_ack_req_tid;
126	  wire [11:0] blk_ack_req_ssn;
127	  reg [11:0] rx_ht_aggr_ssn;
128	  `DEBUG_PREFIX reg rx_ht_aggr_flag;
129	  `DEBUG_PREFIX reg rx_ht_aggr_last_flag;
130	
131	  reg [6:0] bitmap_count;
132	  reg [127:0] blk_ack_bitmap_mem;
133	  `DEBUG_PREFIX reg ampdu_rx_start_reg;
134	  `DEBUG_PREFIX reg reset_blk_ack_bitmap_mem;
135	
136	  `DEBUG_PREFIX reg [1:0] tx_dpram_op_counter;
137	
138	  // `DEBUG_PREFIX wire [2:0] num_data_ofdm_symbol;
139	  // reg  [2:0] num_data_ofdm_symbol_reg;
140	  // `DEBUG_PREFIX wire [2:0] ackcts_n_sym;
141	  // reg  [2:0] ackcts_n_sym_reg;
142	  `DEBUG_PREFIX reg signed [8:0] ackcts_time;
143	  reg signed [7:0] sifs_time_reg;
144	
145	  `DEBUG_PREFIX reg [14:0] recv_ack_timeout_top;
146	
147	  `DEBUG_PREFIX reg [15:0] duration_new;
148	  `DEBUG_PREFIX reg [1:0]  FC_type_new;
149	  `DEBUG_PREFIX reg [3:0]  FC_subtype_new;
150	  `DEBUG_PREFIX reg is_data_received;
151	  `DEBUG_PREFIX reg is_management_received;
152	  `DEBUG_PREFIX reg is_blockackreq_received;
153	  `DEBUG_PREFIX reg is_pspoll_received;
154	  `DEBUG_PREFIX reg is_rts_received;
155	
156	  reg [14:0] send_ack_wait_top_scale;
157	  reg [14:0] send_ack_wait_top_scale_lock;
158	  reg [14:0] recv_ack_sig_valid_timeout_top_scale;
159	  reg [14:0] recv_ack_timeout_top_adj_scale;
160	  `DEBUG_PREFIX reg retrans_started;
161	
162	  assign tx_control_state_out  = tx_control_state;
163	  assign tx_control_state_idle =((tx_control_state==IDLE) && (~retrans_started));
164	
165	  assign retrans_limit = (max_num_retrans[3]?max_num_retrans[2:0]:tx_pkt_retrans_limit);
166	
167	  assign is_data =        ((FC_type==2'b10)?1:0);
168	  assign is_qosdata =     (((FC_type==2'b10) && (FC_subtype[3]==1'b1))?1:0);
169	  assign is_management =  (((FC_type==2'b00) && (FC_subtype!=4'b1110))?1:0);
170	  assign is_blockackreq = (((FC_type==2'b01) && (FC_subtype==4'b1000))?1:0);
171	  assign is_blockackresp= (((FC_type==2'b01) && (FC_subtype==4'b1001) && (signal_len==32))?1:0);
172	  assign is_pspoll =      (((FC_type==2'b01) && (FC_subtype==4'b1010))?1:0);
173	  assign is_rts =         (((FC_type==2'b01) && (FC_subtype==4'b1011) && (signal_len==20))?1:0);
174	  assign is_ack =         (((FC_type==2'b01) && (FC_subtype==4'b1101) && (signal_len==14))?1:0);
175	
176	  assign ack_cts_is_ongoing = ((tx_control_state==PREP_ACK) || (tx_control_state==SEND_DFL_ACK) || (tx_control_state==SEND_BLK_ACK));
177	  assign ackcts_signal_parity = (~(^ackcts_rate));//because the cts and ack pkt length field is always 14: 1110 that always has 3 1s
178	  assign ackcts_signal_len = 14;
179	  assign blkack_signal_len = 32;
180	
181	  assign blk_ack_req_tid = blk_ack_req_ctrl[15:12];
182	  assign blk_ack_req_ssn = blk_ack_req_ssc[15:4];
183	
184	  // // this is not needed. we should assume the peer always send us ack @ 6Mbps
185	  // n_sym_len14_pkt # (
186	  // ) n_sym_len14_pkt_i0 (
187	  //   .ht_flag(signal_rate[7]),
188	  //   .rate_mcs(signal_rate[3:0]),
189	  //   .n_sym(num_data_ofdm_symbol)
190	  // );
191	
192	  // // this is not needed. we should assume the peer always send us ack @ 6Mbps
193	  // n_sym_len14_pkt # (
194	  // ) n_sym_len14_pkt_i1 (
195	  //   .ht_flag(0),
196	  //   .rate_mcs(ackcts_rate),
197	  //   .n_sym(ackcts_n_sym)
198	  // );
199	
200		always @(posedge clk)                                             
201	    begin
202	      if (!rstn)
203	      // Synchronous reset (active low)                                       
204	        begin
205	          wea<=0;
206	          addra<=0;
207	          dina<=0;
208	          ack_timeout_count<=0;
209	          ack_addr <=0;
210	          send_ack_count <= 0;
211	          ack_tx_flag<=0;
212	          tx_control_state  <= IDLE;
213	          tx_control_state_old <= IDLE;
214	          tx_try_complete<=0;
215	          tx_status<=0;
216	          num_retrans_lock <= 0;
217	          blk_ack_resp_ssn_lock <= 0;
218	          blk_ack_bitmap_lock <= 0;
219	          num_retrans<=0;
220	          start_retrans<=0;
221	          start_tx_ack<=0;
222	          retrans_started<=0;
223	          retrans_in_progress<=0;
224	          retrans_trigger<=0;
225	          tx_dpram_op_counter<=0;
226	          recv_ack_timeout_top<=0;
227	          duration_new<=0;
228	          FC_type_new<=0;
229	          FC_subtype_new<=0;
230	          duration_received<=0;
231	          duration_standard<=0;
232	          FC_more_frag_received<=0;
233	          is_data_received<=0;
234	          is_management_received<=0;
235	          is_blockackreq_received<=0;
236	          is_pspoll_received<=0;
237	          is_rts_received<=0;
238	
239	          rx_ht_aggr_ssn<=0;
240	          rx_ht_aggr_flag<=0;
241	          rx_ht_aggr_last_flag<=0;
242	
243	          // num_data_ofdm_symbol_reg <= 0;
244	          // ackcts_n_sym_reg <= 0;
245	
246	          bitmap_count <=0;
247	          reset_blk_ack_bitmap_mem <=0;
248	
249	          send_ack_wait_top_scale <=0;
250	          send_ack_wait_top_scale_lock <=0;
251	          recv_ack_sig_valid_timeout_top_scale <= 0;
252	          recv_ack_timeout_top_adj_scale <= 0;
253	        end
254	      else begin
255	        tx_control_state_old<=tx_control_state;
256	        
257	        // ackcts_rate <= (cts_torts_rate[4]?signal_rate[3:0]:cts_torts_rate[3:0]); // this is not needed. we should assume the peer always send us ack @ 6Mbps
258	        // ackcts_rate <= 4'b1011; //6Mbps.
259	        ackcts_rate <= cts_torts_rate[3:0];
260	
261	        // ackcts_time <= preamble_sig_time + ofdm_symbol_time*({4'd0,ackcts_n_sym_reg}); 
262	        ackcts_time       <= preamble_sig_time + ofdm_symbol_time*({4'd0,3'd6}); // ack/cts use 6 ofdm symbols at 6Mbps
263	        sifs_time_reg     <= sifs_time;
264	        duration_standard <= (duration_received - ackcts_time - sifs_time_reg);
265	
266	        tx_status <= {blk_ack_bitmap_lock, blk_ack_resp_ssn_lock, num_retrans_lock};
267	
268	        // num_data_ofdm_symbol_reg <= num_data_ofdm_symbol;
269	        // ackcts_n_sym_reg <= ackcts_n_sym;
270	
271	        send_ack_wait_top_scale <= ((send_ack_wait_top-relative_decoding_latency)*`COUNT_SCALE);
272	        recv_ack_sig_valid_timeout_top_scale <= (recv_ack_sig_valid_timeout_top*`COUNT_SCALE);
273	        recv_ack_timeout_top_adj_scale <= (recv_ack_timeout_top_adj*`COUNT_SCALE);
274	
275	        ampdu_rx_start_reg <= ampdu_rx_start;
276	        blk_ack_bitmap_mem <= (ampdu_rx_start_reg == 0 && ampdu_rx_start == 1)?0:blk_ack_bitmap_mem;
277	
278	        case (tx_control_state)
279	          IDLE: begin
280	            ack_tx_flag<=0;
281	            wea<=0;
282	            addra<=0;
283	            dina<=0;
284	            ack_timeout_count<=0;
285	            send_ack_count <= 0;
286	            tx_try_complete<=0;
287	            start_retrans<=0;
288	            start_tx_ack<=0;
289	            tx_dpram_op_counter<=0;
290	            retrans_trigger<=0;
291	            recv_ack_timeout_top<=0;
292	            duration_new<=0;
293	            FC_type_new<=0;
294	            FC_subtype_new<=0;
295	            ack_addr <= addr2;
296	            duration_received<=(duration[15]==0?duration[14:0]:0);
297	            FC_more_frag_received<=FC_more_frag;
298	            is_data_received<=is_data;
299	            is_management_received<=is_management;
300	            is_blockackreq_received<=is_blockackreq;
301	            is_pspoll_received<=is_pspoll;
302	            is_rts_received<=is_rts;
303	            // tx_status<=tx_status; //maintain status from state RECV_ACK for ARM reading
304	            // num_retrans<=num_retrans;
305	            // retrans_in_progress<=retrans_in_progress;
306	            bitmap_count <= 0;
307	
308	            // This is the last packet of aggregation and fcs valid
309	            if ( rx_ht_aggr_last && fcs_valid && is_qosdata && (self_mac_addr==addr1) && (ampdu_rx_tid == qos_tid || ampdu_rx_tid_disable) )
310	              begin
311	                // In case the last packet from A-MPDU makes it through
312	                if(rx_ht_aggr_flag == 0) begin
313	                    rx_ht_aggr_flag <= 1;
314	                    rx_ht_aggr_ssn <= SC_seq_num;
315	                // Sometimes, MPDUs come out-of-order (i.e. random seq_no) and in such cases, the starting sequence number should take the smallest value
316	                end else if(SC_seq_num < rx_ht_aggr_ssn) begin
317	                    rx_ht_aggr_ssn <= SC_seq_num;
318	                end
319	                blk_ack_bitmap_mem[SC_seq_num[6:0]] <= 1'b1;
320	                rx_ht_aggr_last_flag <= 1;
321	                send_ack_wait_top_scale_lock <= send_ack_wait_top_scale;
322	                tx_control_state <= PREP_ACK;
323	              end
324	            // This is the last packet of aggregation and fcs NOT valid
325	            else if ( rx_ht_aggr_last && fcs_in_strobe == 1 && fcs_valid == 0 ) 
326	              begin
327	                // Since this MPDU is not valid, only send a block ack if there were previously received valid MPDUs
328	                if(rx_ht_aggr_flag == 1) begin
329	                    rx_ht_aggr_last_flag <= 1;
330	                    send_ack_wait_top_scale_lock <= send_ack_wait_top_scale;
331	                    tx_control_state <= PREP_ACK;
332	                end
333	              end
334	            //8.3.1.4 ACK frame format: The RA field of the ACK frame is copied from the Address 2 field of the immediately previous individually
335	            //addressed data, management, BlockAckReq, BlockAck, or PS-Poll frames.
336	            else if ( fcs_valid && ((is_data&&(~is_qosdata))||(is_qosdata&&(~^qos_ack_policy))||is_management||is_blockackreq||is_pspoll||(is_rts&&(!cts_torts_disable)))
337	                           && (self_mac_addr==addr1)) // send ACK will not back to this IDLE until the last IQ sample sent.
338	              begin
339	                  if(rx_ht_aggr && (ampdu_rx_tid == qos_tid || ampdu_rx_tid_disable)) begin
340	                      // First packet from aggregated A-MPDU
341	                      if(rx_ht_aggr_flag == 0) begin
342	                          rx_ht_aggr_flag <= 1;
343	                          rx_ht_aggr_ssn <= SC_seq_num;
344	                      // Sometimes, MPDUs come out-of-order (i.e. random seq_no) and in such cases, the starting sequence number should take the smallest value
345	                      end else if(SC_seq_num < rx_ht_aggr_ssn) begin
346	                          rx_ht_aggr_ssn <= SC_seq_num;
347	                      end
348	                      blk_ack_bitmap_mem[SC_seq_num[6:0]] <= 1'b1;
349	                  end else begin
350	                      send_ack_wait_top_scale_lock <= send_ack_wait_top_scale;
351	                      tx_control_state  <= (ack_tx_disable?tx_control_state:PREP_ACK); //we also send cts (if rts is received) in PREP_ACK status
352	                  end
353	              end
354	            //else if ( pulse_tx_bb_end && tx_pkt_type[0]==1 && (core_state_old!=PREP_ACK) )// need to recv ACK! We need to miss this pulse_tx_bb_end intentionally when send ACK, because ACK don't need ACK
355	            //else if ( phy_tx_done && (core_state_old!=PREP_ACK) )// need to recv ACK! We need to miss this pulse_tx_bb_end intentionally when send ACK, because ACK don't need ACK
356	            else if ( phy_tx_done && cts_toself_bb_is_ongoing==0 ) // because PREP_ACK won't be back until phy_tx_done. So here phy_tx_done must be from high layer
357	              begin
358	                  retrans_started<=0;
359	                  if (tx_pkt_need_ack==1) // continue to actual ACK receiving
360	                      begin
361	                      tx_control_state<= RECV_ACK_WAIT_TX_BB_DONE;
362	                      addra<=2;
363	                      tx_try_complete<=0;
364	                      retrans_in_progress<=1;
365	                      end
366	                  else
367	                      begin
368	                      tx_try_complete<=1;
369	                      num_retrans_lock <= num_retrans;
370	                      blk_ack_resp_ssn_lock <= 0;
371	                      blk_ack_bitmap_lock <= 1;
372	                      num_retrans<=0;
373	                      retrans_in_progress<=0;
374	                      end
375	              end
376	            else if ((quit_retrans == 1) && (retrans_in_progress == 1)) 
377	              begin 
378	                  tx_try_complete<=1;
379	                  num_retrans_lock <= num_retrans;
380	                  blk_ack_resp_ssn_lock <= 0;
381	                  blk_ack_bitmap_lock <= 0;
382	                  num_retrans<=0;
383	                  retrans_in_progress<=0;
384	                  retrans_started<=0;
385	              end 
386	            else if ((backoff_done==1) && (retrans_in_progress==1) && (retrans_started==0))
387	              begin
388	                  if(quit_retrans) begin
389	                    tx_try_complete<=1;
390	                    num_retrans_lock <= num_retrans;
391	                    blk_ack_resp_ssn_lock <= 0;
392	                    blk_ack_bitmap_lock <= 0;
393	                    num_retrans<=0;
394	                    retrans_in_progress<=0;
395	                    retrans_started<=0;
396	                  end else begin
397	                    start_retrans <= 1 ;
398	                    retrans_started <= 1;
399	                  end
400	              end
401	          end
402	
403	          PREP_ACK: begin // data is calculated by calc_phy_header C program
404	            if (tx_core_is_ongoing) begin
405	              rx_ht_aggr_flag <= 0;
406	              rx_ht_aggr_last_flag <= 0;
407	              tx_control_state  <= IDLE;
408	            end else begin
409	              ack_tx_flag<=1;
410	              // ack_addr <= ack_addr;
411	              // tx_try_complete<=tx_try_complete;
412	              // tx_status<=tx_status; //maintain status from state RECV_ACK for ARM reading
413	              // num_retrans<=num_retrans;
414	              // start_retrans<=start_retrans;
415	              // retrans_in_progress<=retrans_in_progress;
416	              // tx_dpram_op_counter<=tx_dpram_op_counter;
417	              // recv_ack_timeout_top<=recv_ack_timeout_top;
418	
419	              FC_type_new<=2'b01;
420	              if ((rx_ht_aggr_last_flag && (ampdu_rx_tid == qos_tid || ampdu_rx_tid_disable)) || (is_blockackreq_received && (ampdu_rx_tid == blk_ack_req_tid || ampdu_rx_tid_disable))) begin
421	                duration_new<= duration_extra+0;
422	                FC_subtype_new<=4'b1001;
423	
424	                // Prepare block ack response bitmap
425	                if(rx_ht_aggr_last_flag) begin
426	                    blk_ack_bitmap_lock[bitmap_count[5:0]] <= blk_ack_bitmap_mem[(rx_ht_aggr_ssn[6:0]+bitmap_count)];
427	                    // Clear past bitmap history
428	                    if(bitmap_count < 32)
429	                        blk_ack_bitmap_mem[(rx_ht_aggr_ssn[6:0]+bitmap_count+7'd64)] <= 0;
430	                end else begin
431	                    blk_ack_bitmap_lock[bitmap_count[5:0]] <= blk_ack_bitmap_mem[(blk_ack_req_ssn[6:0]+bitmap_count)];
432	                    // Clear past bitmap history
433	                    if(bitmap_count < 32)
434	                        blk_ack_bitmap_mem[(blk_ack_req_ssn[6:0]+bitmap_count+7'd64)] <= 0;
435	                end
436	                if(bitmap_count < 63)
437	                    bitmap_count <= bitmap_count + 1;
438	
439	              //standard: For ACK frames sent by non-QoS STAs, if the More Fragments bit was equal to 0 in the Frame Control field
440	              //of the immediately previous individually addressed data or management frame, the duration value is set to 0.
441	              end else begin
442	                FC_subtype_new <= (is_rts_received?(4'b1100):(4'b1101));
443	
444	                //standard: In other ACK frames sent by non-QoS STAs, the duration value is the value obtained from the Duration/ID
445	                //field of the immediately previous data, management, PS-Poll, BlockAckReq, or BlockAck frame minus the
446	                //time, in microseconds, required to transmit the ACK frame and its SIFS interval.
447	                //we use 6M for ack(14byte): n_ofdm=6=(22+14*8)/24; time_us=20(preamble+SIGNAL)+6*4=44;
448	                if ( ((is_data_received||is_management_received)&&(FC_more_frag_received==1)) || is_rts_received ) begin
449	                  duration_new<= duration_extra+((duration_standard<=0)?0:duration_standard);
450	                end else begin //pspoll doesn't carry duration. instead it carries AID. no sense to calculate duration based on AID
451	                  duration_new<=duration_extra+0;
452	                end
453	              end
454	
455	              ack_timeout_count <= ( ( ack_timeout_count != send_ack_wait_top_scale_lock )?(ack_timeout_count + 1):ack_timeout_count );
456	              tx_control_state  <= ( ( ack_timeout_count != send_ack_wait_top_scale_lock )?tx_control_state:((rx_ht_aggr_last_flag||is_blockackreq_received) ? SEND_BLK_ACK : SEND_DFL_ACK) );
457	              start_tx_ack <= ( ( ack_timeout_count != send_ack_wait_top_scale_lock )? 0:1);
458	            end
459	          end
460	
461	          SEND_DFL_ACK: begin
462	            //send_ack_count <= ( send_ack_count!=4?(send_ack_count + 1):send_ack_count );
463	            // wea <= (send_ack_count<4?1:0);
464	            start_tx_ack <= 0; //wea <= 1; // replace wea by start_tx_ack, start_tx_ack is only one clock
465	            //addra <= send_ack_count; // no longer need addra, directly output to the tx core
466	            tx_control_state <=  (phy_tx_done?IDLE:tx_control_state);
467	            if(bram_addr==0) begin//if (send_ack_count==0) begin
468	                //dina<={32'h0, 32'h000001cb}; // rate 6M len 14
469	                dina<={32'h0, 14'd0, ackcts_signal_parity, ackcts_signal_len, 1'b0, ackcts_rate};
470	            end else if (bram_addr==2) begin//(send_ack_count==2) begin
471	                //dina<={ack_addr[31:0], 32'h000000d4};
472	                dina<={ack_addr[31:0], duration_new, 8'd0, FC_subtype_new, FC_type_new, 2'd0};
473	            end else if (bram_addr==3) begin//(send_ack_count==3) begin
474	                dina<={48'h0,ack_addr[47:32]};
475	            end
476	          end
477	
478	          SEND_BLK_ACK: begin
479	            start_tx_ack <= 0;
480	            tx_control_state <= (phy_tx_done?IDLE:tx_control_state);
481	            rx_ht_aggr_flag <= (phy_tx_done?0:rx_ht_aggr_flag);
482	            rx_ht_aggr_last_flag <= (phy_tx_done?0:rx_ht_aggr_last_flag);
483	            if(bram_addr==0) begin
484	                dina<={32'h0, 14'd0, ackcts_signal_parity, blkack_signal_len, 1'b0, ackcts_rate};		// block ack and normal ack have identical signal parity and bit rate
485	            end else if (bram_addr==2) begin
486	                dina<={ack_addr[31:0], duration_new, 8'd0, FC_subtype_new, FC_type_new, 2'd0};
487	            end else if (bram_addr==3) begin
488	                dina<={self_mac_addr,ack_addr[47:32]};
489	            end else if (bram_addr==4) begin
490	                if(rx_ht_aggr_last_flag) begin
491	                    dina<={blk_ack_bitmap_lock[31:0], rx_ht_aggr_ssn, ampdu_rx_tid_disable?qos_tid:ampdu_rx_tid, 4'd0, 7'd0, 4'b0010, 1'd0};
492	                end else begin
493	                    dina<={blk_ack_bitmap_lock[31:0], blk_ack_req_ssn, ampdu_rx_tid_disable?blk_ack_req_tid:ampdu_rx_tid, 4'd0, 7'd0, 4'b0010, 1'd0};
494	                end
495	            end else if (bram_addr==5) begin
496	                dina<={32'h0, blk_ack_bitmap_lock[63:32]};
497	            end
498	          end
499	
500	          RECV_ACK_WAIT_TX_BB_DONE: begin
501	            // ack_tx_flag<=ack_tx_flag;
502	            // recv_ack_timeout_top<=recv_ack_timeout_top;
503	
504	            // addra<=addra;
505	
506	            tx_dpram_op_counter <= ( tx_dpram_op_counter!=3?(tx_dpram_op_counter + 1):tx_dpram_op_counter );
507	            if(tx_ht_aggr==0 && tx_dpram_op_counter==2) begin
508	                wea <= 1;
509	                dina <= {douta[63:12], 1'b1, douta[10:0]};
510	            end else begin
511	                wea <= 0;
512	                dina <= douta;
513	            end
514	
515	            // send_ack_count <= send_ack_count;
516	            // ack_addr <= ack_addr;
517	            // ack_timeout_count<=ack_timeout_count;
518	            // // tx_status<=tx_status; //maintain status from state RECV_ACK for ARM reading
519	            // num_retrans<=num_retrans;
520	            // tx_try_complete<=tx_try_complete;
521	            // start_retrans<=start_retrans;
522	            // retrans_in_progress<=retrans_in_progress;
523	
524	            if (pulse_tx_bb_end) begin
525	                tx_control_state<= RECV_ACK_WAIT_SIG_VALID;
526	            end 
527	            // else begin
528	            //     tx_control_state<= tx_control_state;
529	            // end
530	            
531	          end
532	
533	          RECV_ACK_WAIT_SIG_VALID: begin
534	            // ack_tx_flag<=ack_tx_flag;
535	            // wea<=wea;
536	            // addra<=addra;
537	            // dina<=dina;
538	            // send_ack_count <= send_ack_count;
539	            // ack_addr <= ack_addr;
540	            // tx_dpram_op_counter<=tx_dpram_op_counter;
541	            // recv_ack_timeout_top<=recv_ack_timeout_top;
542	
543	            ack_timeout_count<= ( (sig_valid && (signal_len==14||signal_len==32))?0:(ack_timeout_count+1) );
544	            if ( (ack_timeout_count<recv_ack_sig_valid_timeout_top_scale) && sig_valid && (signal_len==14||signal_len==32) ) begin //before timeout, we detect a sig valid, signal length field is ACK/BLK_ACK
545	                tx_control_state<= RECV_ACK;
546	                // tx_try_complete<=tx_try_complete;
547	                // tx_status<=tx_status;
548	                // num_retrans<=num_retrans;
549	                // start_retrans<=start_retrans;
550	                // retrans_in_progress<=retrans_in_progress;
551	                // ack_timeout_count<=0;
552	                if(signal_len==14)
553	                   recv_ack_timeout_top <= (({4'd6, 2'd0})*`NUM_CLK_PER_US)+recv_ack_timeout_top_adj_scale;	// ack/cts uses 6 ofdm symbols at 6Mbps
554	                else if(signal_len==32)
555	                   recv_ack_timeout_top <= (({4'd12,2'd0})*`NUM_CLK_PER_US)+recv_ack_timeout_top_adj_scale;	// blk_ack_resp uses 12 ofdm symbols at 6Mbps
556	            end else if ( ack_timeout_count==recv_ack_sig_valid_timeout_top_scale ) begin // sig valid timeout
557	                tx_control_state<= IDLE;
558	                if  ((num_retrans==retrans_limit) || (retrans_limit==0)) begin// should not run into this state. but just in case
559	                    tx_try_complete<=1;
560	                    // tx_status<={1'b1,num_retrans};
561	                    num_retrans_lock <= num_retrans;
562	                    blk_ack_resp_ssn_lock <= 0;
563	                    blk_ack_bitmap_lock <= 0;
564	                    num_retrans<=0;
565	                    // start_retrans<=start_retrans;
566	                    retrans_in_progress<=0;
567	                end else begin
568	                    // tx_try_complete<=tx_try_complete;
569	                    // tx_status<=tx_status;
570	                    num_retrans<=num_retrans+1;
571	                    retrans_trigger<=1;// start retransmission if ack did not arrive in time --
572	                    // retrans_in_progress<=retrans_in_progress;
573	                end
574	            end 
575	            // else begin
576	            //     tx_control_state<= tx_control_state;
577	            //     tx_try_complete<=tx_try_complete;
578	            //     // tx_status<=tx_status; //maintain status from state RECV_ACK for ARM reading
579	            //     num_retrans<=num_retrans;
580	            //     start_retrans<=start_retrans;
581	            //     retrans_in_progress<=retrans_in_progress;
582	            // end
583	          end
584	
585	          RECV_ACK: begin
586	            // ack_tx_flag<=ack_tx_flag;
587	            // wea<=wea;
588	            // addra<=addra;
589	            // dina<=dina;
590	            // send_ack_count <= send_ack_count;
591	            // ack_addr <= ack_addr;
592	            // tx_dpram_op_counter<=tx_dpram_op_counter;
593	            // recv_ack_timeout_top <= recv_ack_timeout_top;
594	
595	            ack_timeout_count<=ack_timeout_count+1;
596	            // Detection of a normal ack packet is sufficient to acknowledge a traffic. However for aggregation traffic, a valid block ack response is required.
597	            if ( (ack_timeout_count<recv_ack_timeout_top) && (((recv_ack_fcs_valid_disable|fcs_in_strobe) && is_ack) || (fcs_valid && is_blockackresp)) && (self_mac_addr==addr1)) begin//before timeout, we detect a ACK type frame fcs valid
598	                tx_control_state<= IDLE;
599	                tx_try_complete<=1;
600	                // tx_status<={1'b0,num_retrans};
601	                num_retrans_lock <= num_retrans;
602	                if (is_blockackresp) begin
603	                    blk_ack_resp_ssn_lock <= blk_ack_resp_ssn;
604	                    blk_ack_bitmap_lock <= blk_ack_resp_bitmap;
605	                end else begin
606	                    blk_ack_resp_ssn_lock <= 0;
607	                    blk_ack_bitmap_lock <= 1;
608	                end
609	                num_retrans<=0;
610	                // start_retrans<=start_retrans;
611	                retrans_in_progress<=0;
612	            end else if ( ack_timeout_count==recv_ack_timeout_top ) begin// timeout
613	                tx_control_state<= IDLE;
614	                if  ((num_retrans==retrans_limit) || (retrans_limit==0)) begin// should not run into this state. but just in case
615	                    tx_try_complete<=1;
616	                    // tx_status<={1'b1,num_retrans};
617	                    num_retrans_lock <= num_retrans;
618	                    blk_ack_resp_ssn_lock <= 0;
619	                    blk_ack_bitmap_lock <= 0;
620	                    num_retrans<=0;
621	                    // start_retrans<=start_retrans;
622	                    retrans_in_progress<=0;
623	                end else begin
624	                    // tx_try_complete<=tx_try_complete;
625	                    // tx_status<=tx_status;
626	                    num_retrans<=num_retrans+1;
627	                    retrans_trigger<=1; // start retranmission if ack did not receive in time -- 
628	                    // retrans_in_progress<=retrans_in_progress;
629	                end
630	            end 
631	            // else begin
632	            //     tx_control_state<= tx_control_state;
633	            //     tx_try_complete<=tx_try_complete;
634	            //     // tx_status<=tx_status; //maintain status from state RECV_ACK for ARM reading
635	            //     num_retrans<=num_retrans;
636	            //     start_retrans<=start_retrans;
637	            //     retrans_in_progress<=retrans_in_progress;
638	            // end
639	
640	          end
641	
642	        endcase
643	      end
644	    end
645	
646		endmodule
